package api

import (
	"fmt"
	"runtime"
	"time"

	"github.com/dgraph-io/badger/v4"
	"github.com/imroc/req/v3"
	"github.com/kamiertop/videodown/logger"
)

const (
	douyinCookieKey = "douyin_cookie"
)

type Douyin struct {
	logger *logger.Logger
	client *req.Client
	db     *badger.DB
	webId  struct {
		value       string
		lastUpdated time.Time
	}
	msToken struct {
		value       string    // msToken的值
		lastUpdated time.Time // 最后更新时间
	}
}

func New(logger *logger.Logger, db *badger.DB) *Douyin {
	return &Douyin{
		logger: logger.WithName("Douyin"),
		client: req.C().EnableAutoDecompress(),
		db:     db,
	}
}

func (d *Douyin) setKey(key, value string) error {
	return d.db.Update(func(txn *badger.Txn) error {
		return txn.Set([]byte(key), []byte(value))
	})
}

func (d *Douyin) getKey(key string) (string, error) {
	var value string

	return value, d.db.View(func(txn *badger.Txn) error {
		item, err := txn.Get([]byte(key))
		if err != nil {
			return err
		}
		return item.Value(func(val []byte) error {
			value = string(val)
			return nil
		})
	})
}

func (d *Douyin) getCookie() (string, error) {
	return d.getKey(douyinCookieKey)
}

func (d *Douyin) setCookie(cookie string) error {
	return d.setKey(douyinCookieKey, cookie)
}

// 从cookie中获取UIFID
func (d *Douyin) getUiFid() (string, error) {
	return "", nil
}

// getMsToken 保存至 Douyin 中，每次登录都重新请求，然后每10分钟刷新一次
func (d *Douyin) getMsToken() (string, error) {
	// TODO 校验是否需要刷新

	resp, err := d.client.R().
		SetQueryParam("ms_appid", "6383").
		SetQueryParam("msToken", "").
		SetHeaders(map[string]string{
			"User-Agent":               userAgent(),
			"Sec-Fetch-Site":           "cross-site",
			"Sec-Fetch-Storage-Access": "active",
			"Accept":                   "*/*",
			"Accept-Language":          "zh-CN,zh;q=0.9",
			"Content-Type":             "application/json; charset=UTF-8",
			"Origin":                   "https://www.douyin.com",
			"Referer":                  "https://www.douyin.com/",
			"Priority":                 "u=1, i",
			"Sec-CH-UA":                `"Google Chrome";v="146", "Not:A-Brand";v="24", "Chromium";v="146"`,
			"Sec-CH-UA-Mobile":         "?0",
			"Sec-CH-UA-Platform":       fmt.Sprintf(`"%s"`, runtime.GOOS),
			"Sec-Fetch-Dest":           "empty",
			"Sec-Fetch-Mode":           "cors",
		}).
		SetBodyJsonMarshal(map[string]any{
			"version":       1,
			"magic":         538969122,
			"dataType":      8,
			"url":           0,
			"tspFormClient": time.Now().UnixMilli(),
			"strData":       "",
		}).
		Post("https://mssdk.bytedance.com/web/common")
	if err != nil {
		return "", fmt.Errorf("request msToken api error: %w", err)
	}
	d.msToken.value = resp.GetHeader("Set-Cookie")[8:]
	d.msToken.lastUpdated = time.Now()

	return d.msToken.value, nil
}
